import fetch from"node-fetch";import{writeIcon}from"./write-icon.js";import{STUB_PATH_PHP}from"../utils/stub-path.js";const BULK_URL="https://ppicons.tsnc.tech/icons?icon=all";export async function generateAllIcons(t,o=!1){const e=await fetch(BULK_URL);if(!e.ok)throw new Error(`Could not fetch list: ${e.statusText} – ${BULK_URL}`);const n=await e.json();console.log(`➡  Recibidos ${n.length} iconos. Generando…`);const s=[],c=[];let i=[];for(const e of n){const n=writeIcon(e,t,STUB_PATH_PHP,o).then(t=>s.push(t)).catch(t=>c.push(`${e.name}: ${t.message}`));i.push(n),i.length>=10&&(await Promise.allSettled(i),i=[])}return await Promise.allSettled(i),{ok:s,fail:c}}